// Lee el CSV de Google Sheets (fuente de verdad del inventario), filtra, ordena, resume y devuelve.
// Inputs (todos opcionales excepto si se busca por numero):
//   numero (string): '1'..'74' o 'B1'..'B20' — busqueda puntual
//   estado (string): 'disponible' (default) | 'reservado' | 'vendido' | 'todos'
//   tamano_min / tamano_max (number, m2): 0 = sin limite
//   presupuesto_contado_max / presupuesto_credito_max (number, CLP): 0 = sin limite
//   sector (string): 'numeradas' | 'lote_b' | 'todas' (default)
//   solo_destacadas (boolean): true = solo parcelas con estrella
//   orden (string): 'destacadas_primero' (default) | 'precio_asc' | 'precio_desc' | 'tamano_asc' | 'tamano_desc'
//   max_resultados (number): default 5, clamp a [1, 30]

const csvText = (($input.first().json.data ?? $input.first().json.body) || '').toString();
if (!csvText || csvText.length < 100) {
  return [{ json: {
    error: 'csv_fetch_failed',
    tool_output_text: 'No pude consultar el inventario en este momento. Deja que Diego te confirme por WhatsApp.',
  }}];
}

const q = $('Execute Workflow Trigger').first().json || {};
const numero = (q.numero ?? '').toString().trim().toUpperCase();
const estado = ((q.estado ?? 'disponible').toString().trim().toLowerCase()) || 'disponible';
const tamano_min = Number(q.tamano_min) || 0;
const tamano_max = Number(q.tamano_max) || 0;
const presupuesto_contado_max = Number(q.presupuesto_contado_max) || 0;
const presupuesto_credito_max = Number(q.presupuesto_credito_max) || 0;
const sector = ((q.sector ?? 'todas').toString().trim().toLowerCase()) || 'todas';
const solo_destacadas = !!q.solo_destacadas;
const orden = ((q.orden ?? 'destacadas_primero').toString().trim().toLowerCase()) || 'destacadas_primero';
const max_resultados = Math.max(1, Math.min(30, Number(q.max_resultados) || 5));

// ---- CSV parser (maneja comillas y comas dentro de campos) ----
function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i+1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i+1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const rows = parseCsv(csvText);

const parseMoney = (s) => {
  if (!s) return null;
  const t = s.toString();
  if (t.includes('#DIV') || t.includes('#REF') || t.includes('#VALUE')) return null;
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseSize = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseCuotaMensual = (s) => parseMoney(s);
const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return e || 'desconocido';
};

const parcelas = [];
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  const destacada = ((r[0] || '').toString().trim() === '⭐');
  parcelas.push({
    numero: lote.toUpperCase(),
    destacada,
    estado: normalizeEstado(r[2]),
    tamano_m2: parseSize(r[3]),
    precio_contado: parseMoney(r[6]),
    descuento_pct: (r[7] || '').toString().replace(/[^0-9]/g, '') ? parseInt(r[7].replace(/[^0-9]/g, ''), 10) : null,
    precio_credito: parseMoney(r[9]),
    pie_minimo: parseMoney(r[10]),
    cuota_mensual: parseCuotaMensual(r[11]),
    es_lote_b: lote.toUpperCase().startsWith('B'),
  });
}

// ---- Resumen global (antes de cualquier filtro, sobre todo el sheet) ----
function buildResumenGlobal(all) {
  const disp = all.filter(p => p.estado === 'disponible');
  const tramos = {};
  const tamanos = {};
  const numeradas = disp.filter(p => !p.es_lote_b).length;
  const loteB = disp.filter(p => p.es_lote_b).length;
  let precMin = null, precMax = null, cuotaMin = null, cuotaMax = null;
  for (const p of disp) {
    if (p.precio_contado !== null) {
      const key = p.precio_contado.toString();
      tramos[key] = (tramos[key] || 0) + 1;
      if (precMin === null || p.precio_contado < precMin) precMin = p.precio_contado;
      if (precMax === null || p.precio_contado > precMax) precMax = p.precio_contado;
    }
    if (p.tamano_m2 !== null) {
      const key = p.tamano_m2.toString();
      tamanos[key] = (tamanos[key] || 0) + 1;
    }
    if (p.cuota_mensual !== null) {
      if (cuotaMin === null || p.cuota_mensual < cuotaMin) cuotaMin = p.cuota_mensual;
      if (cuotaMax === null || p.cuota_mensual > cuotaMax) cuotaMax = p.cuota_mensual;
    }
  }
  return {
    total_inventario: all.length,
    total_disponibles: disp.length,
    total_reservadas: all.filter(p => p.estado === 'reservado').length,
    total_vendidas: all.filter(p => p.estado === 'vendido').length,
    destacadas_disponibles: disp.filter(p => p.destacada).length,
    destacadas_ids: disp.filter(p => p.destacada).map(p => p.numero),
    disponibles_por_tramo_contado: tramos,
    disponibles_por_tamano_m2: tamanos,
    disponibles_por_sector: { numeradas, lote_b: loteB },
    rango_precio_contado: { min: precMin, max: precMax },
    rango_cuota_mensual: { min: cuotaMin, max: cuotaMax },
  };
}
const resumen_global = buildResumenGlobal(parcelas);

// --- Modo 1: busqueda puntual por numero ---
if (numero) {
  const match = parcelas.find(p => p.numero === numero);
  if (!match) {
    return [{ json: {
      query: { numero },
      resumen_global,
      total_matches: 0,
      tool_output_text: `No encuentro la parcela ${numero} en el inventario. Las numeradas van del 1 al 74 y hay lotes de ampliacion B1 al B20.`,
    }}];
  }
  const disp = match.estado === 'disponible';
  const resv = match.estado === 'reservado';
  const vend = match.estado === 'vendido';
  let text;
  if (disp) {
    const contado = match.precio_contado ? `$${match.precio_contado.toLocaleString('es-CL')}` : 'precio a confirmar';
    const credito = match.precio_credito ? `$${match.precio_credito.toLocaleString('es-CL')}` : 'precio a confirmar';
    const pie = match.pie_minimo ? `$${match.pie_minimo.toLocaleString('es-CL')}` : 'pie a confirmar';
    const cuota = match.cuota_mensual ? `$${match.cuota_mensual.toLocaleString('es-CL')} mensuales (indexadas en UF)` : 'cuota a confirmar';
    const dest = match.destacada ? ' ⭐ (destacada)' : '';
    text = `La parcela ${match.numero}${dest} esta disponible. Tamano ${match.tamano_m2} m². Contado ${contado} (dcto ${match.descuento_pct}%). Credito ${credito} con 50% pie (${pie}) + 36 cuotas de ${cuota}.`;
  } else if (resv) {
    text = `La parcela ${match.numero} esta reservada actualmente. Si te interesa, te aviso cuando quede libre o te muestro alternativas parecidas.`;
  } else if (vend) {
    text = `La parcela ${match.numero} ya esta vendida. Te puedo mostrar alternativas parecidas en tamano y precio.`;
  } else {
    text = `La parcela ${match.numero} no tiene estado claro en el inventario. Deja que Diego te lo confirme.`;
  }
  return [{ json: {
    query: { numero },
    resumen_global,
    total_matches: 1,
    parcela: match,
    tool_output_text: text,
  }}];
}

// --- Modo 2: filtrado ---
let filtered = parcelas;
if (estado !== 'todos') {
  filtered = filtered.filter(p => p.estado === estado);
}
if (sector === 'numeradas') filtered = filtered.filter(p => !p.es_lote_b);
else if (sector === 'lote_b') filtered = filtered.filter(p => p.es_lote_b);
if (tamano_min > 0) filtered = filtered.filter(p => (p.tamano_m2 ?? 0) >= tamano_min);
if (tamano_max > 0) filtered = filtered.filter(p => (p.tamano_m2 ?? Infinity) <= tamano_max);
if (presupuesto_contado_max > 0) filtered = filtered.filter(p => p.precio_contado !== null && p.precio_contado <= presupuesto_contado_max);
if (presupuesto_credito_max > 0) filtered = filtered.filter(p => p.precio_credito !== null && p.precio_credito <= presupuesto_credito_max);
if (solo_destacadas) filtered = filtered.filter(p => p.destacada);

// Orden configurable
const byNumero = (a, b) => a.numero.localeCompare(b.numero, 'es', { numeric: true });
const sorters = {
  'destacadas_primero': (a, b) => {
    if (a.destacada !== b.destacada) return a.destacada ? -1 : 1;
    const pa = a.precio_contado ?? Infinity;
    const pb = b.precio_contado ?? Infinity;
    if (pa !== pb) return pa - pb;
    return byNumero(a, b);
  },
  'precio_asc': (a, b) => {
    const pa = a.precio_contado ?? Infinity;
    const pb = b.precio_contado ?? Infinity;
    if (pa !== pb) return pa - pb;
    return byNumero(a, b);
  },
  'precio_desc': (a, b) => {
    const pa = a.precio_contado ?? -Infinity;
    const pb = b.precio_contado ?? -Infinity;
    if (pa !== pb) return pb - pa;
    return byNumero(a, b);
  },
  'tamano_asc': (a, b) => {
    const ta = a.tamano_m2 ?? Infinity;
    const tb = b.tamano_m2 ?? Infinity;
    if (ta !== tb) return ta - tb;
    return byNumero(a, b);
  },
  'tamano_desc': (a, b) => {
    const ta = a.tamano_m2 ?? -Infinity;
    const tb = b.tamano_m2 ?? -Infinity;
    if (ta !== tb) return tb - ta;
    return byNumero(a, b);
  },
};
const sorter = sorters[orden] || sorters['destacadas_primero'];
filtered.sort(sorter);

const shown = filtered.slice(0, max_resultados);
const total_matches = filtered.length;

// Resumen filtrado (para reasoning del agente)
function buildResumenFiltrado(set) {
  if (set.length === 0) return { vacio: true };
  const tramos = {};
  let precMin = null, precMax = null;
  let destacadas = 0, numeradas = 0, loteB = 0;
  const tamanos = {};
  for (const p of set) {
    if (p.destacada) destacadas++;
    if (p.es_lote_b) loteB++; else numeradas++;
    if (p.precio_contado !== null) {
      const key = p.precio_contado.toString();
      tramos[key] = (tramos[key] || 0) + 1;
      if (precMin === null || p.precio_contado < precMin) precMin = p.precio_contado;
      if (precMax === null || p.precio_contado > precMax) precMax = p.precio_contado;
    }
    if (p.tamano_m2 !== null) {
      const key = p.tamano_m2.toString();
      tamanos[key] = (tamanos[key] || 0) + 1;
    }
  }
  return {
    destacadas,
    por_sector: { numeradas, lote_b: loteB },
    por_tramo_contado: tramos,
    por_tamano_m2: tamanos,
    rango_precio_contado: { min: precMin, max: precMax },
    numeros: set.map(p => p.numero),
  };
}
const resumen_filtrado = buildResumenFiltrado(filtered);

// tool_output_text narrativo
let text;
if (total_matches === 0) {
  text = `No tengo parcelas que cumplan esos criterios ahora mismo. ¿Relajamos algun filtro (presupuesto o tamano) o te aviso cuando entre una?`;
} else {
  const fmtM = (n) => n ? `$${n.toLocaleString('es-CL')}` : '—';
  const lines = shown.map(p => {
    const star = p.destacada ? '⭐ ' : '';
    const pCont = fmtM(p.precio_contado);
    const pCred = fmtM(p.precio_credito);
    return `${star}Parcela ${p.numero} (${p.tamano_m2} m²) — contado ${pCont} / credito ${pCred}`;
  });
  const extra = total_matches > max_resultados ? ` (muestro ${max_resultados} de ${total_matches})` : '';
  text = `Tengo ${total_matches} parcela${total_matches > 1 ? 's' : ''} que calza${total_matches > 1 ? 'n' : ''}${extra}:\n${lines.join('\n')}`;
}

return [{ json: {
  query: {
    estado, tamano_min, tamano_max, presupuesto_contado_max, presupuesto_credito_max,
    sector, solo_destacadas, orden, max_resultados,
  },
  resumen_global,
  resumen_filtrado,
  total_matches,
  shown_count: shown.length,
  parcelas: shown,
  tool_output_text: text,
}}];
